  // =============================================
  // SECTION 2: Combo System
  // =============================================
  describe('Combo System', () => {
    test('C3: three consecutive same elements detected and removed', () => {
      const player = createPlayer('P1');
      player.character = { comboRewards: { tier1: { atkBonus: 150 } } };
      player.elementQueue = ['Fire', 'Ice', 'Fire', 'Fire', 'Fire'];
      const tokens = [
        createToken({ id: 0, owner: 'P1', atk: 10 }),
        createToken({ id: 1, owner: 'P1', atk: 10 }),
        createToken({ id: 2, owner: 'P1', atk: 10 }),
      ];

      const result = checkCombo(player, tokens);
      expect(result.comboType).toBe('C3');
      expect(player.comboCount).toBe(1);
      // After removal, the 3 consecutive fires should be gone
      expect(player.elementQueue).not.toContainEqual('Fire');
    });

    test('C4: four different elements detected and removed', () => {
      const player = createPlayer('P1');
      player.character = { comboRewards: { tier1: { atkBonus: 150 } } };
      player.elementQueue = ['Fire', 'Ice', 'Grass', 'Rock'];
      const tokens = [
        createToken({ id: 0, owner: 'P1', atk: 10 }),
      ];

      const result = checkCombo(player, tokens);
      expect(result.comboType).toBe('C4');
    });

    test('C3 takes priority over C4 when both possible', () => {
      const player = createPlayer('P1');
      player.character = { comboRewards: { tier1: { atkBonus: 150 } } };
      // Queue where C3 (Fire,Fire,Fire) exists alongside 4 different
      player.elementQueue = ['Ice', 'Grass', 'Rock', 'Fire', 'Fire', 'Fire'];
      const tokens = [
        createToken({ id: 0, owner: 'P1', atk: 10 }),
      ];

      const result = checkCombo(player, tokens);
      expect(result.comboType).toBe('C3');
    });

    test('C3 Tier1 combo adds +150 ATK to all tokens', () => {
      const player = createPlayer('P1');
      player.character = { comboRewards: { tier1: { atkBonus: 150 } } };
      player.elementQueue = ['Fire', 'Fire', 'Fire'];
      const tokens = [
        createToken({ id: 0, owner: 'P1', atk: 10 }),
        createToken({ id: 1, owner: 'P1', atk: 20 }),
      ];

      checkCombo(player, tokens);
      expect(tokens[0].atk).toBe(160); // 10 + 150
      expect(tokens[1].atk).toBe(170); // 20 + 150
    });

    test('Cascading combo: removal triggers re-scan', () => {
      const player = createPlayer('P1');
      player.character = { comboRewards: { tier1: { atkBonus: 150 } } };
      // After removing first C3 [Ice,Ice,Ice], we get [Fire,Fire,Fire] which is another C3
      player.elementQueue = ['Ice', 'Ice', 'Ice', 'Fire', 'Fire', 'Fire'];
      const tokens = [createToken({ id: 0, owner: 'P1', atk: 0 })];

      checkCombo(player, tokens);
      expect(player.comboCount).toBe(2); // cascading triggered second combo
    });

    test('maxComboTier enforced by Level', () => {
      const player = createPlayer('P1');
      player.level = 1; // maxComboTier = 1
      player.character = { comboRewards: { tier1: { atkBonus: 150 }, tier2: { multiplier: 2 }, tier3: { multiplier: 1.5 } } };
      player.comboCount = 1;
      // Next combo would be tier 2, but level 1 caps at tier 1
      const result = checkCombo(player, []);
      // Tier 2 should not be applied at level 1
    });
  });

  // =============================================
  // SECTION 2: Combat (Kick)
  // =============================================
  describe('Combat (Kick)', () => {
    test('attacker on defender tile (non-safe) deals damage', () => {
      const state = createGameState();
      const attacker = createToken({ id: 0, owner: 'P1', atk: 75 });
      const defender = createToken({ id: 1, owner: 'P2', position: 10, atk: 20 });
      defender.position = attacker.position;

      state.players['P2'].hp = 1000;
      processKick(state, attacker, defender);
      expect(state.players['P2'].hp).toBe(925); // 1000 - 75
    });

    test('ATK=0 deals no damage', () => {
      const state = createGameState();
      const attacker = createToken({ id: 0, owner: 'P1', atk: 0 });
      const defender = createToken({ id: 1, owner: 'P2', atk: 20 });
      defender.position = attacker.position;

      state.players['P2'].hp = 1000;
      processKick(state, attacker, defender);
      expect(state.players['P2'].hp).toBe(1000);
    });

    test('kicked token pushed to nearest safe zone behind', () => {
      const state = createGameState();
      const attacker = createToken({ id: 0, owner: 'P1', atk: 50, position: 20 });
      const defender = createToken({ id: 1, owner: 'P2', atk: 10, position: 20 });

      processKick(state, attacker, defender);
      // Token should be at a safe zone behind position 20
      const safeZones = state.board.tiles.filter(t => t.type === 'Safe');
      const safeBehind = safeZones.filter(t => t.id < defender.position).pop();
      expect(defender.position).toBe(safeBehind.id);
    });

    test('kick increments attacker kickCount', () => {
      const state = createGameState();
      const attacker = createToken({ id: 0, owner: 'P1', atk: 50 });
      const defender = createToken({ id: 1, owner: 'P2', atk: 10 });
      defender.position = attacker.position;

      attacker.kickCount = 0;
      processKick(state, attacker, defender);
      expect(attacker.kickCount).toBe(1);
    });

    test('cannot kick on Safe Zone tile', () => {
      const state = createGameState();
      const attacker = createToken({ id: 0, owner: 'P1', atk: 50 });
      const defender = createToken({ id: 1, owner: 'P2' });
      defender.position = attacker.position;
      state.board.tiles[attacker.position].type = 'Safe';

      const result = processKick(state, attacker, defender);
      expect(result.kicked).toBe(false);
    });
  });

