  describe('MAG & Ultimate', () => {
    test('MAG accumulates on non-Affinity landing', () => {
      const player = createPlayer('P1');
      player.character = { affinity: 'Fire', mag: 10 };
      player.mag = 0;
      // Landing on Ice (non-affinity) — handled in tile effect
      player.mag += player.character.mag;
      expect(player.mag).toBe(10);
    });

    test('MAG capped at magCap', () => {
      const player = createPlayer('P1');
      player.magCap = 100;
      player.mag = 95;
      const gain = 10;
      const actualGain = Math.min(gain, player.magCap - player.mag);
      player.mag += actualGain;
      expect(player.mag).toBe(100);
      expect(actualGain).toBe(5);
    });
  });

