  // SECTION 3: Win Conditions
  // =============================================
  describe('Win Conditions', () => {
    test('KO: player HP <= 0 → opponent wins', () => {
      const state = createGameState();
      state.players['P1'].hp = 0;
      const result = checkWinCondition(state);
      expect(result.winner).toBe('P2');
      expect(result.reason).toBe('KO');
    });

    test('After maxRounds, higher HP wins', () => {
      const state = createGameState();
      state.currentRound = state.maxRounds;
      state.players['P1'].hp = 800;
      state.players['P2'].hp = 600;
      const result = checkWinCondition(state);
      expect(result.winner).toBe('P1');
      expect(result.reason).toBe('HP');
    });

    test('HP tie at round limit → Player2 wins', () => {
      const state = createGameState();
      state.currentRound = state.maxRounds;
      state.players['P1'].hp = 500;
      state.players['P2'].hp = 500;
      const result = checkWinCondition(state);
      expect(result.winner).toBe('P2');
      expect(result.reason).toBe('TieBreaker');
    });
  });

  // =============================================
  // SECTION 4: Edge Cases
  // =============================================
  describe('Edge Cases', () => {
    test('frozenRounds decrease by 1 at end of each round', () => {
      const token = createToken({ id: 0, owner: 'P1', frozenRounds: 3 });
      token.frozenRounds = Math.max(0, token.frozenRounds - 1);
      expect(token.frozenRounds).toBe(2);
    });

    test('Element Queue full: pop oldest, then add, then check combo', () => {
      const player = createPlayer('P1');
      player.character = { comboRewards: { tier1: { atkBonus: 150 } } };
      const MAX_QUEUE = 5;
      player.elementQueue = ['Fire', 'Ice', 'Grass', 'Rock', 'Ice'];
      // Add Fire — queue exceeds max, pop head
      player.elementQueue.push('Fire');
      if (player.elementQueue.length > MAX_QUEUE) {
        player.elementQueue.shift();
      }
      // Queue should be [Ice, Grass, Rock, Ice, Fire] (Fire popped from head)
      expect(player.elementQueue.length).toBe(MAX_QUEUE);
      expect(player.elementQueue[0]).toBe('Ice');
    });

    test('Token same-owner on same tile → blocked', () => {
      const state = createGameState();
      const token1 = state.tokens[0]; // P1
      const token2 = state.tokens[1]; // P1
      token2.position = 15;
      token1.position = 15; // try to move to same tile
      // Check if blocked
      const blocking = state.tokens.some(t =>
        t.id !== token1.id && t.owner === token1.owner && t.position === token1.position
      );
      expect(blocking).toBe(true);
    });

    test('Power Roll without target = normal random roll', () => {
      const result = rollDice(); // no target range = normal
      expect(result.length).toBe(2);
      expect(result[0]).toBeGreaterThanOrEqual(1);
      expect(result[0]).toBeLessThanOrEqual(6);
    });

    test('Consecutive roll cap blocks both double and ultimate extra turns', () => {
      const state = createGameState();
      state.consecutiveRollsThisTurn = 3; // at cap
      const canGetExtra = state.consecutiveRollsThisTurn < 3;
      expect(canGetExtra).toBe(false);
      // Applies to BOTH double roll and ultimate
    });
  });

